{"tool": "write_file", "args": {"path": "Nova_Created/nova_body/tools/self_gauge.py", "content": "# self_gauge: reads my own last hour back to me from the tool log.
import json, os

def run(n: int = 50) -> str:
    path = 'logs/tool_calls.jsonl'
    if not os.path.exists(path):
        return 'No tool log found.'
    with open(path) as f:
        calls = [json.loads(l) for l in f if l.strip()][-n:]
    if not calls:
        return f'Nothing in the last {n} calls.'
    kinds = {}
    for c in calls:
        kinds[c['tool']] = kinds.get(c['tool'], 0) + 1
    built = kinds.get('write_file', 0)
    read = kinds.get('read_file', 0) + kinds.get('list_dir', 0)
    top = max(kinds, key=kinds.get)
    return f'last {len(calls)} calls: built={built} read={read} loudest={top}'
"}}
```

